form:Form.form:Scripts:
		function onLoad()
{
	// Obtiene el estado del inscripto y si esta aprobado o no
	var estado, aprobado;
	if (Ctrl('LIST'))
	{
		estado = Ctrl('LIST').GetSelectAttrValue('c_estado');
		aprobado = Ctrl('LIST').GetSelectAttrValue('c_estado_aprob'); 
	}else
	{
		estado = Ctrl('c_estado').GetXValue();
		aprobado = Ctrl('c_estado_aprob').GetXValue();
	}

  CtrlEnabled('APROBADO', false);
	CtrlEnabled('REPROBADO', false);
	CtrlEnabled('DELETE', true);
	CtrlEnabled('INSCRIPTO', false);
	CtrlEnabled('CANCELADO', false);
	CtrlEnabled('CURSADO', false);
	CtrlEnabled('DELETE', false);

 	if (estado != 'CAN')
	{
		switch (aprobado)
		{
			case 'A':
				CtrlEnabled('APROBADO', false);
				CtrlEnabled('REPROBADO', true);
				break;
			case 'R':
				CtrlEnabled('APROBADO', true);
				CtrlEnabled('REPROBADO', false);
				break;
			default:
				CtrlEnabled('APROBADO', true);
				CtrlEnabled('REPROBADO', true);
				break;
		}
	}	

	if (estado == 'CAN')
	{
		CtrlEnabled('DELETE', true);
		CtrlEnabled('CANCELADO', false);
		CtrlEnabled('INSCRIPTO', true);
		CtrlEnabled('CURSADO', false);
	}	
	if (estado == 'INS')
	{
		CtrlEnabled('DELETE', false);
		CtrlEnabled('CANCELADO', true);
		CtrlEnabled('INSCRIPTO', false);
		CtrlEnabled('CURSADO', true);
	}
	if (estado == 'CUR')
	{
		CtrlEnabled('DELETE', false);
		CtrlEnabled('CANCELADO', true);
		CtrlEnabled('INSCRIPTO', false);
		CtrlEnabled('CURSADO', false);
	}

	if (Ctrl('f_hoy'))
	{
		Ctrl('f_hoy').SetXValue(date2str(Now()));
	}	
}
